                                        <div><span className="font-bold">Pay to:</span> {storeSettings.promptPayNumber || '0994979199'}</div>
                                        <div><span className="font-bold">Amount:</span> ฿{(selectedOrder ? selectedOrder.totalAmount : cartTotal).toLocaleString()}</div>
